  /* ============ RULES ============ */
  'rules.eyebrow': { uk: 'Правила', en: 'Rules', pl: 'Zasady', ru: 'Правила' },
  'rules.h1': { uk: 'Правила платформи', en: 'Platform rules', pl: 'Zasady platformy', ru: 'Правила платформы' },
  'rules.general.h2': { uk: 'Загальні положення', en: 'General provisions', pl: 'Postanowienia ogólne', ru: 'Общие положения' },
  'rules.general.p': {
    uk: 'Vintage Hall — це платформа, де продавці та покупці здійснюють угоди між собою. Vintage Hall не є стороною купівлі-продажу, але модерує лоти та забезпечує дотримання правил.',
    en: 'Vintage Hall is a platform where sellers and buyers transact with each other. Vintage Hall is not a party to the sale, but moderates lots and enforces the rules.',
    pl: 'Vintage Hall to platforma, na której sprzedawcy i kupujący zawierają transakcje między sobą. Vintage Hall nie jest stroną kupna-sprzedaży, ale moderuje loty i dba o przestrzeganie zasad.',
    ru: 'Vintage Hall — это платформа, где продавцы и покупатели совершают сделки между собой. Vintage Hall не является стороной купли-продажи, но модерирует лоты и обеспечивает соблюдение правил.',
  },
  'rules.buyers.h2': { uk: 'Для покупців', en: 'For buyers', pl: 'Dla kupujących', ru: 'Для покупателей' },
  'rules.buyers.p1': {
    uk: 'Кожна ставка на аукціоні є зобов\'язуючою. Якщо ви виграли аукціон — ви зобов\'язані завершити покупку протягом 48 годин або зв\'язатися з продавцем. Неоплата виграних лотів може призвести до блокування акаунта.',
    en: 'Every auction bid is binding. If you win an auction, you must complete the purchase within 48 hours or contact the seller. Failure to pay for won lots may lead to account suspension.',
    pl: 'Każda oferta na aukcji jest wiążąca. Jeśli wygrałeś aukcję — musisz sfinalizować zakup w ciągu 48 godzin lub skontaktować się ze sprzedawcą. Brak zapłaty za wygrane loty może skutkować blokadą konta.',
    ru: 'Каждая ставка на аукционе является обязывающей. Если вы выиграли аукцион — вы обязаны завершить покупку в течение 48 часов или связаться с продавцом. Неоплата выигранных лотов может привести к блокировке аккаунта.',
  },
  'rules.buyers.p2': {
    uk: 'Повернення товару можливе протягом 24 годин після отримання, якщо стан речі суттєво не відповідає опису та фотографіям у лоті.',
    en: 'Returns are possible within 24 hours of receipt if the item\'s condition significantly differs from the description and photos in the lot.',
    pl: 'Zwrot towaru jest możliwy w ciągu 24 godzin od otrzymania, jeśli stan rzeczy istotnie nie odpowiada opisowi i zdjęciom w locie.',
    ru: 'Возврат товара возможен в течение 24 часов после получения, если состояние вещи существенно не соответствует описанию и фотографиям в лоте.',
  },
  'rules.sellers.h2': { uk: 'Для продавців', en: 'For sellers', pl: 'Dla sprzedawców', ru: 'Для продавцов' },
  'rules.sellers.p1': {
    uk: 'Продавець зобов\'язаний чесно описувати стан речі: матеріал, дефекти, реставрації. Фотографії мають відображати реальний стан лоту. За свідомо неправдивий опис передбачене видалення лоту та блокування акаунта.',
    en: 'The seller must describe the item\'s condition honestly: material, defects, restorations. Photos must reflect the lot\'s actual condition. Knowingly false descriptions lead to lot removal and account suspension.',
    pl: 'Sprzedawca ma obowiązek uczciwie opisać stan rzeczy: materiał, wady, renowacje. Zdjęcia muszą odzwierciedlać rzeczywisty stan lotu. Za świadomie nieprawdziwy opis przewidziane jest usunięcie lotu i blokada konta.',
    ru: 'Продавец обязан честно описывать состояние вещи: материал, дефекты, реставрации. Фотографии должны отражать реальное состояние лота. За заведомо ложное описание предусмотрено удаление лота и блокировка аккаунта.',
  },
  'rules.sellers.p2': {
    uk: 'Комісія платформи складає 5% від фінальної ціни продажу. Комісія стягується з продавця після успішного завершення угоди.',
    en: 'The platform fee is 5% of the final sale price. The fee is charged to the seller after the deal is successfully completed.',
    pl: 'Prowizja platformy wynosi 5% końcowej ceny sprzedaży. Prowizja pobierana jest od sprzedawcy po pomyślnym zakończeniu transakcji.',
    ru: 'Комиссия платформы составляет 5% от финальной цены продажи. Комиссия взимается с продавца после успешного завершения сделки.',
  },
  'rules.auctions.h2': { uk: 'Аукціони', en: 'Auctions', pl: 'Aukcje', ru: 'Аукционы' },
